INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('136ac116-2e2e-88ae-1fda-575e35194225', 'pt', 'CASA VEGETARIANA', 'Uma cozinha vegetariana de gosto fácil, para avós e netos, vegetarianos ou não, para todos os gostos!', 'Através da magia da brasa, despertamos sabores novos e outros que, retidos na nossa memória, nos transportam para o conforto de outros tempos. Frutas, Cogumelos, Legumes, Aromáticos, Azeites, Especiarias, Queijos e outros, são diretamente fornecidos pelos vendedores e produtores, nossos vizinhos, no Mercado do Bolhão.')
