-- ALEXANDRA MATIAS
INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('a6fdbb63-a810-3e50-712c-745ecd9c2dbc', 'pt', 'ALEXANDRA MATIAS', 'Destino obrigatório para quem aprecia peças de luxo vintage.', 'Na emblemática Rua Castilho, no centro de Lisboa, a Alexandra Matias Jewelry é mais do que uma joalharia: é um lugar onde o luxo encontra a história. Entre peças assinadas por Cartier, Van Cleef & Arpels, Bulgari, Tiffany; relógios de prestígio Rolex ou Patek Philippe e joias antigas, cada detalhe foi escolhido pela sua autenticidade e valor intemporal.
Com a curadoria de Alexandra Matias, gemóloga e Avaliadora Oficial, a nossa Loja convida-o a descobrir peças intemporais com história.
Esperamos pela sua visita, para que viva Lisboa com um brilho único, no ambiente sofisticado e acolhedor da nossa Loja.')
