-- BAIRRO DO AVILLEZ
INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('5b8d39e3-e29e-4349-c1f2-3ffb71dd4332', 'pt', 'BAIRRO DO AVILLEZ', 'O BAIRRO MAIS ATÍPICO E SURPREENDENTE DE LISBOA', 'O Bairro do Avillez, em pleno Chiado, é um espaço de 1000m2 criado pelo chef José Avillez, que reúne diferentes conceitos de restauração inspirados nos melhores sabores portugueses. Este é o mais atípico dos bairros lisboetas. 
No Bairro do Avillez há uma surpresa em cada esquina. O mundo de José Avillez não cabe numa só morada, é todo um universo dedicado à criatividade e aos melhores sabores portugueses: há uma Taberna surpreendente para quem gosta de comer bem, o Páteo mais espectacular da cidade, com a melhor cozinha portuguesa, o Mini Bar, o restaurante e bar gastronómico onde não falta música e animação; e a Pizzaria Lisboa, com os melhores sabores mediterrânicos.
“O Bairro do Avillez é para todos os que gostam de comer bem e ainda querem ser surpreendidos”! - José Avillez.

Taberna / Esplanada (+351) 210 998 320
Páteo (+351) 215 830 290
Mini Bar (+351) 211 305 393 minibar.pt
Pizzaria Lisboa (+351) 211 554 945 pizzarialisboa.pt')
