-- BARBOUR
INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('0178bf45-a60d-6a63-c2aa-6c2d409985d4', 'pt', 'BARBOUR', 'Os clássicos casacos encerados ainda são fabricados manualmente na fábrica de Simonside.', 'Os nossos tartans exclusivos transmitem uma herança histórica. Um selo de autenticidade. Um motivo de orgulho. Transportados ao logo de gerações, através do nosso negócio familiar.
Criados em colaboração com o mestre de tartans Kinloch Anderson, estes padrões traçam o nome da família Barbour desde o século XIII, em Ayrshire, na costa oeste da escócia.
Desenhados para refletir a nossa herança e os laços familiares. Os nossos tartans estão presentes em muitas das nossas peças, desde camisas, a cachecóis, e claro, nas nossas icônicas peças de outerwear. Quer seja num padrão integral, num pequeno detalhe ou forro, são a marca de uma verdadeira peça Barbour.')
ON CONFLICT (place_id, locale) DO UPDATE SET
  name = COALESCE(NULLIF(place_translations.name, ''), EXCLUDED.name),
  short_description = COALESCE(NULLIF(place_translations.short_description, ''), EXCLUDED.short_description),
  full_description = COALESCE(NULLIF(place_translations.full_description, ''), EXCLUDED.full_description),
  updated_at = now();

