-- CASA DA GUIA
INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('309c4823-931d-3cf4-40fe-36db87b2417e', 'pt', 'CASA DA GUIA', 'Onde o bom gosto é uma arte.', 'Onde o bom gosto 
é uma arte
CASA DA GUIA é um dos locais únicos e mais bonitos que alguma vez poderá visitar em Cascais.
A Quinta dos Condes de Alcáçovas preserva, ainda, o seu emblemático palacete do século XIX, totalmente recuperado pelo arquiteto Claudio Wanderley.
Um local com uma variedade de atrativos perfeito para os seus encontros, reuniões, compras, refeições ou simplesmente relaxar.
Restaurantes, Cafés e Pastelaria estão envolvidos pelo verde e a mais espantosa vista sobre o Oceano Atlântico da Costa de Cascais.
Encontra ainda Lojas e Serviços de onde se destacam Moda, Decoração, Galeria de Arte, Design de Interiores, Moda Desporto, Viveiros de Plantas, Cabeleireiro, Centro de Estética, Parafarmácia, Livros Antigos, Mercearia Gourmet, Anfiteatro, Lounge para Eventos, Parque Infantil e muito... muito mais!')
ON CONFLICT (place_id, locale) DO UPDATE SET
  name = COALESCE(NULLIF(place_translations.name, ''), EXCLUDED.name),
  short_description = COALESCE(NULLIF(place_translations.short_description, ''), EXCLUDED.short_description),
  full_description = COALESCE(NULLIF(place_translations.full_description, ''), EXCLUDED.full_description),
  updated_at = now();

-- CASA DA MÚSICA
INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('de4d786f-0603-78f2-b3e9-e3fe1a830fc7', 'pt', 'CASA DA MÚSICA', 'Edifício de forma poliédrica projectado pelo arquitecto holandês Rem Koolhaas, a Casa da Música, inaugurada em 2005', 'As visitas guiadas são uma óptima forma de conhecer a Casa da Música nas suas múltiplas vertentes. Durante cerca de uma hora, um guia preparado conduz os visitantes pelos diversos espaços do edifício, explicando a forma como a arquitectura, as funcionalidades e a programação artística se relacionam.')
