INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('3938d3a6-3436-7099-83b8-09750de836d5', 'pt', 'CASA DE CHÁ DA BOA NOVA', 'Fazemos uma cozinha etno-emocional, sem limites geográficos à criação e à influência, mas intimamente ligada às nossas raízes culturais', 'Com duas estrelas Michelin, é muito mais do que um restaurante. Quem entra apercebe-se, de imediato, da dimensão do horizonte através das suas imponentes janelas, elevando ao máximo as expectativas do momento. A singularidade do edifício constitui um ‘paradigma da inserção da arquitetura na paisagem’.;')
