-- CASTANHEIRO BOUTIQUE HOTEL
INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('6f062374-db43-3734-de8d-7074ff7774e7', 'pt', 'CASTANHEIRO BOUTIQUE HOTEL', 'Tem como ex-libris uma piscina panorâmica e um jacuzzi no topo do terraço com vistas deslumbrantes sobre a baía do Funchal.', 'O Castanheiro Boutique Hotel é resultado de um cuidadoso restauro arquitetónico combinando um design inovador com altos padrões de serviço, onde a gastronomia e a atenção ao cliente são ponto de honra a cada momento da estadia.')
