-- CONFEITARIA NACIONAL
INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('11cb6922-d4fb-d14a-693e-2e78d68d773b', 'pt', 'CONFEITARIA NACIONAL', 'Casa fundada em 1829', 'Fundada em 1829, é propriedade da mesma família há seis gerações e mantém a decoração do século XIX.
Com um serviço rápido e agradável, é o lugar perfeito para comprar todo o tipo de biscoitos, pastelaria e ainda chocolates e café de marca própria. 
Todas as receitas são mantidas inalteradas ao longo dos anos. 
No primeiro andar encontra-se disponível salão de chá com refeições.')
