INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('085b5132-8765-b2d0-9891-c4b5d7bda103', 'pt', 'COQUINE', 'Mulheres que ouvem o coração, que ultrapassam os limites, que lutam pelos seus sonhos e nunca deixam de acreditar em si mesmas.', 'Porque há detalhes que dão às mulheres a confiança necessária para criar o seu estilo pessoal. Peças que pretendem encapsular memórias e que podemos coordenar, misturar e fazer parte de nós. Em prata, para que resistam ao tempo, tal como os momentos que queremos guardar para sempre.')
