INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('ff79e155-4004-b98e-ed87-e868e26a110a', 'pt', 'DAVID ROSAS', 'A loja David Rosas na Avenida da Boavista foi a primeira loja da marca, tendo sido inaugurada em 1984.', 'A David Rosas é reconhecida como uma das marcas mais importantes do setor do luxo em Portugal. Os nossos clientes têm oportunidade de experienciar algo verdadeiramente único: o prazer intemporal das peças de luxo exclusivas.')
