-- EL CORTE INGLÉS
INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('c3dcaff7-4cff-d8ee-1d76-9ff629e7dda0', 'pt', 'EL CORTE INGLÉS', 'O seu destino de compras em Portugal', 'Descubra as melhores marcas, ofertas exclusivas e experiências únicas, tudo num só lugar.
O El Corte Inglés é um department store de referência em Portugal e Espanha, reconhecido pela excelência do seu serviço e pela diversidade da sua oferta. Reúne, num único espaço, moda, beleza, tecnologia, produtos gourmet, decoração e muito mais, tudo das melhores marcas nacionais e internacionais.
Para os visitantes estrangeiros não residentes, o Cartão 10% Reward e Tax Free são a forma ideal de tirar o máximo partido das suas compras: um cartão exclusivo para turistas, que oferece 10% em centenas de marcas e o reembolso imediato do Tax Free nas nossas lojas, uma vantagem exclusiva do El Corte Inglés.
Se procura um serviço exclusivo e personalizado contacte o International Desk, situado no Piso 0 da Loja de Lisboa.
Esperamos por si!')
ON CONFLICT (place_id, locale) DO UPDATE SET
