-- GRANADO
INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('06ab6433-c3c8-d124-38e4-a8b306624806', 'pt', 'GRANADO', 'A perfumaria mais tradicional do Brasil.', 'A Conserveira de Lisboa surge em 1942 e a sua história é uma de perseverança, de determinação e, sobretudo, uma história de família. Fernando da Silva Ferreira trabalha na Mercearia do Minho, precursora da Conserveira de Lisboa e criada em 1930 e, através da gestão das suas poupanças, consegue ir adquirindo quotas da sociedade. Desde então, a história atribulada da Conserveira de Lisboa confunde-se, ainda que marcada por diversas mudanças a nível societário e atravessando várias crises – desde o fim da guerra do Ultramar ao aumento exponencial dos congelados até ao aparecimento das grandes superfícies comerciais de retalho -, com a história da família Ferreira. Uma história marcada pela capacidade de inovar, quando empreendedorismo era ainda um palavrão, pela visão estratégica, quando estratégia era somente um termo técnico de guerra, pelo desenho cuidado das latas, quando todos pensavam no design como um refúgio para estudantes frustrados de arquitetura ou de belas-artes. 
A Conserveira de Lisboa, enquanto negócio familiar, assenta o seu modo de funcionamento na herança que transitou de geração em geração e que excede em muito o espaço físico da empresa. Essa herança é património imaterial da sua história. E ter uma história é sobretudo respeitar a matriz desse passado, resistir aos chavões efémeros da moda e ter sempre presente a missão que deu origem e norteou a empresa: proporcionar aos seus clientes os melhores produtos aos melhores preços. Não somos gourmet, recusamos aderir a qualquer compromisso que envolva maximizar o lucro através 
do sacrifício dos valores pelos quais nos guiamos. Somos uma empresa familiar e isso permite-nos a ousadia romântica de ter o cliente como norte magnético de todas as fases do nosso trabalho. 
Fazemo-lo há mais de oitenta anos, a montante da gestão por objetivos, da ditadura do marketing e da imposição das tendências. 
E tem resultado, talvez porque sempre acreditámos que a autenticidade é o nosso melhor ingrediente.')
ON CONFLICT (place_id, locale) DO UPDATE SET
  name = COALESCE(NULLIF(place_translations.name, ''), EXCLUDED.name),
  short_description = COALESCE(NULLIF(place_translations.short_description, ''), EXCLUDED.short_description),
  full_description = COALESCE(NULLIF(place_translations.full_description, ''), EXCLUDED.full_description),
  updated_at = now();

