-- JANGAL GASTRO BAR
INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('32a9d5c7-7576-16f5-06e1-221865af30d8', 'pt', 'JANGAL GASTRO BAR', 'Com o mote #rhymeswithall, este jardim urbano convida todos a entrar, descalçar a pressa e respirar devagar.', 'A carta é uma ode à gastronomia mediterrânica, com uma fusão de ícones entre Portugal e Espanha: do bacalhau à tortilha, da costela mendinha às paelhas fumegantes. As opções vegetarianas têm como missão serem, exatamente, escolhas e não opções.')
