-- KARATER – TASTE OF GEORGIA
INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('def3722c-7451-0576-9173-30d4624c07aa', 'pt', 'KARATER – TASTE OF GEORGIA', 'Descobrir os sabores, a alma e a hospitalidade da Georgia no coração do Bairro Alto', 'Karater – Taste of Georgia é o novo ponto de referência da Rua Diário de Notícias. Instalado no antigo espaço da leitaria “Flor da Branca”, recupera com cuidado traços originais de início do século XX, combinando história, arte déco e art nouveau, ao mesmo tempo que celebra a gastronomia, vinhos e cultura georgiana.
Co-fundado por Guram Baghdoshvili, considerado “guardião da gastronomia georgiana”, e Pedro Carvalho, o restaurante é um tributo à autenticidade, à herança cultural e à Lisboa de outrora.
Após duas décadas entre Portugal e a Georgia, o chef regressou com uma proposta única: uma cozinha com coração georgiano e alma portuguesa. O menu é um convite à descoberta: pratos autênticos com toque contemporâneo e ingredientes nacionais, de destaque para vegetais, nozes e beringela, além de clássicos icónicos como Adjaruli Khachapuri, Khinkali e Chakapuli de Borrego.
Com uma carta de vinhos que honra os 8.000 anos de tradição vinícola georgiana, o Karater é também um bar de cocktails de autor que prolonga a viagem pela noite dentro.
Conhecer o Karater é viajar sem sair de Lisboa — uma experiência que une cultura, sabor e hospitalidade num ambiente intemporal.')
ON CONFLICT (place_id, locale) DO UPDATE SET
  name = COALESCE(NULLIF(place_translations.name, ''), EXCLUDED.name),
  short_description = COALESCE(NULLIF(place_translations.short_description, ''), EXCLUDED.short_description),
  full_description = COALESCE(NULLIF(place_translations.full_description, ''), EXCLUDED.full_description),
  updated_at = now();

