-- MUNICÍPIO DE ALMADA
INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('6544ee6f-2a53-0fdd-5649-7b00f3f4ffc1', 'pt', 'MUNICÍPIO DE ALMADA', 'Natural e Cosmopolita para viver, sentir e desfrutar todo o ano!', 'Debruçada sobre o Tejo, de frente para a capital, Almada combina o ritmo tranquilo da natureza em estado puro e da vida ao ar livre, com a energia criativa dos grandes eventos culturais que acontecem todo o ano, testemunho da identidade cosmopolita que caracteriza este concelho. 
Entre património histórico, religioso, militar e cultural, miradouros e uma belíssima oferta gastronómica, este é um território dinâmico, repleto de itinerários de interesse inesperados, dinamizados com recurso às novas tecnologias, de acesso livre. 
Deixe-se levar pelo pulsar da cidade com os inúmeros programas culturais e artísticos de fama internacional, mergulhe no coração da natureza em estado puro e sinta a magia das tradições, e do legado histórico a desaguar na modernidade.')
ON CONFLICT (place_id, locale) DO UPDATE SET
