-- REFUSE
INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('057eaa2d-4c11-2dc2-d6e3-10de6bb12c08', 'pt', 'REFUSE', 'Tornamos compatível o LUXO com o consumo responsável e sustentável.', 'A REFUSE abriu no CHIADO uma loja de roupa e acessórios alguns usados ou novos em STOCK-OFF. Peças exclusivas de enorme qualidade e muito bom gosto, a um preço muito competitivo, cuidadosamente escolhidas para mulher e homem.
Assim se apresenta a REFUSE, na Rua da Horta Seca 24, pertíssimo do Largo de Camões, com venda também pelo Instagram refuse_shop. Mais recentemente e face ao sucesso da 1ª loja abrimos uma 2ª loja em Santa Catarina, na Rua do Poço dos Negros 9.
Na REFUSE, pode encontrar várias marcas de luxo e excecionais, tais como marcas clássicas como Hermès, 
Louis Vuitton, Chanel, Dior, 
Yves Saint Laurent, Celine, Bottega Veneta, Gucci, Etro, Dolce & Gabanna, Givenchy, Balmain, Valentino, Chloe ou marcas contemporâneas como Dries Van Noten, Forte Forte, Acne Studios, Alexander Mcqueen, Proenza Schouler, Missoni, Vince, Ganni, Boss, Hackett, Frescobol, Maxmara, Ulla Johnson, Isabel Marant, IRO, 
Gas Bijoux, entre outras marcas de alta qualidade.
Promovemos o “estar na moda”, com peças absolutamente únicas, mas fazendo-o de uma forma sustentável, contribuindo para a Economia Circular.
A Refuse aparece para tornar compatível o luxo com o consumo responsável e sustentável.')
ON CONFLICT (place_id, locale) DO UPDATE SET
  name = COALESCE(NULLIF(place_translations.name, ''), EXCLUDED.name),
  short_description = COALESCE(NULLIF(place_translations.short_description, ''), EXCLUDED.short_description),
  full_description = COALESCE(NULLIF(place_translations.full_description, ''), EXCLUDED.full_description),
  updated_at = now();

