INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('487e7759-9663-8c5f-f65e-f9e04f4125b9', 'pt', 'SANTO PIZZARIA & STEAKHOUSE', 'No coração da Baixa do Porto, no número 45 da rua que o baptizou, a Rua de Santo Ildefonso, está o Santo.', 'Num ambiente descontraído, mas cuidado, o Santo propõe uma verdadeira day trip a Itália, que pode começar, por exemplo, com uma bruschetta com recheio da época, seguir por pastas finalizadas na roda de Grana Padano ou risottos cremosos e ainda carnes suculentas, mas culminar, quase sempre, num tiramisu preparado à mesa, como manda a tradição.')
