-- TACHO REAL
INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('fe8f8df1-3b01-4e41-9c57-946de60f5aff', 'pt', 'TACHO REAL', 'Levamos os visitantes numa viagem de sabores sempre actuais, sem perderde vista o seu passado Sintrense.', 'O Restaurante Tacho Real, fundado no ano de 1986, encontra-se instalado no edifício do antigo Hotel Victor Sassetti que, durante o Século XIX, era porto de abrigo da aristocracia portuguesa e dos visitantes estrangeiros que acorriam à Vila de Sintra. 
Rodeando-se da sua História – e decorado a preceito – o Restaurante Tacho Real propõe-se a levar os seus visitantes numa viagem de sabores sempre actuais, sem perder de vista o seu passado Sintrense.
Para o efeito, conta com uma lista de vinhos criteriosamente selecionada e uma gastronomia variada. A não perder: o Bife à Tacho Real – naco do lombo inspirado num dos ex libris da gastronomia, que animava a sociedade Sintrense do século XIX, o Filet de bœuf á la Renaissance – e o clássico Perdiz à Gardeza. Destacam-se ainda os Filetes com Molho de Camarão e o Arroz à Angolana. Não deixe de experimentar os doces tradicionais portugueses, desde o Pudim Abade Priscos, ao Arroz Doce; ou, quem sabe, simplesmente acompanhar o entardecer com um aperitivo, numa das esplanadas com mais estórias de Sintra.')
ON CONFLICT (place_id, locale) DO UPDATE SET
  name = COALESCE(NULLIF(place_translations.name, ''), EXCLUDED.name),
  short_description = COALESCE(NULLIF(place_translations.short_description, ''), EXCLUDED.short_description),
  full_description = COALESCE(NULLIF(place_translations.full_description, ''), EXCLUDED.full_description),
  updated_at = now();

