-- TERRA NOVA
INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('f350d743-fd44-7dda-2d68-eec979214e87', 'pt', 'TERRA NOVA', 'O Terra Nova presta homenagem ao bacalhau e à tradição do seu consumo em Portugal.', 'Influenciado pela imensidão da costa portuguesa, o Terra Nova harmoniza o bacalhau com as ostras, acrescentando riqueza gastronómica à sua oferta. Assim, é possível encontrar pratos com um contexto histórico bem vincado, tais como a sopa de bacalhau, a feijoada de bacalhau, bacalhau com broa e ainda ostras ao natural.;')
