-- WISH RESTAURANT & SUSHI
INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('ac95d9fb-6f27-e70e-d8ed-3cca7f6498cf', 'pt', 'WISH RESTAURANT & SUSHI', 'Fusão perfeita de tradição e modernidade, onde a arte culinária japonesa se encontra com a sofisticação da cozinha tradicional.', 'Convidamo-lo a embarcar numa viagem culinária onde cada prato conta uma história e cada momento é cuidadosamente desenhado para encantar. No Wish Restaurante, proporcionamos uma verdadeira celebração dos sentidos, onde cada refeição é um desejo realizado. Venha descobrir a excelência da nossa cozinha connosco. Esperamos por si no Wish Restaurante.;')
