-- WORLD TRG
INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('1e7863ad-c42c-e687-f546-78251f54a08c', 'pt', 'WORLD TRG', 'Real Estate/Relocation/ Property Management', 'Temos o orgulho de oferecer um nível excepcional de serviço aos nossos Clientes
O nosso portfólio de imóveis inclui algumas das casas mais exclusivas e desejáveis da Vila de Cascais e de Portugal.
Desde villas e penthouses deslumbrantes até mansões históricas e propriedades únicas, oferecemos uma ampla variedade de propriedades excepcionais para todos os gostos e orçamentos.

Relocation
A nossa equipa é especializada em investimento e residência em Portugal, especialmente na zona da Grande de Lisboa.
Acreditamos que trabalhar com instituições, diplomatas, militares e famílias privadas, e compreender as suas necessidades quando se trata de entrar ou sair de Portugal, é essencial no seu caminho para uma nova vida longe de casa.
O nosso objetivo é facilitar a sua vida e reduzir todo o stress diário que acompanha a mudança para o exterior.

Gestão de Propriedades
investir com a WORLD TRG é um processo simples e transparente. A nossa equipa e a exclusiva “Plataforma de Gestão – WTRG” garantem que o seu processo de investimento seja simples, claro, recompensador e seguro, oferecendo um portfólio diversificado desde apartamentos citadinos a Villas exclusivas. Cuidaremos do seu investimento com dedicação, comprometimento e profissionalismo!
As propriedades “Managed by WTRG” estão sob o nosso programa de manutenção 24/7 e são fáceis de monitorizar onde quer que esteja, através da nossa exclusiva “Plataforma de Gestão – WTRG”. Comece hoje o seu processo de investimento connosco e experimente a facilidade e segurança de investir em propriedades em Portugal')
ON CONFLICT (place_id, locale) DO UPDATE SET
  name = COALESCE(NULLIF(place_translations.name, ''), EXCLUDED.name),
  short_description = COALESCE(NULLIF(place_translations.short_description, ''), EXCLUDED.short_description),
  full_description = COALESCE(NULLIF(place_translations.full_description, ''), EXCLUDED.full_description),
  updated_at = now();

-- XERJOFF  – Boutique Lisboa
INSERT INTO place_translations (place_id, locale, name, short_description, full_description)
VALUES ('c04152de-c905-b5c7-0fc9-2d9fe25391f0', 'pt', 'XERJOFF  – Boutique Lisboa', 'Alta perfumaria italiana no coração de Lisboa.', 'No coração da cidade de Lisboa, encontra-se a Xerjoff Boutique Lisboa — um verdadeiro destino de luxo para os amantes de fragrâncias exclusivas.
Cada perfume é criado com ingredientes raros, design elegante e um cuidado artesanal que tornam a Xerjoff uma referência mundial em alta perfumaria.
Na Xerjoff Boutique Lisboa, fragrâncias exclusivas combinam-se com um atendimento personalizado, num espaço sofisticado e acolhedor.
Descubra uma nova forma de viver o luxo da perfumaria.')
ON CONFLICT (place_id, locale) DO UPDATE SET
