-- ── 1. XERJOFF – Boutique Lisboa ─────────────────────────────
INSERT INTO place_translations
  (place_id, locale, name, short_description, full_description,
   goldenbook_note, why_we_love_it, insider_tip)
VALUES (
  'c04152de-c905-b5c7-0fc9-2d9fe25391f0', 'es',
  'XERJOFF – Boutique Lisboa',
  'Alta perfumería italiana en el corazón de Lisboa.',
  'En el centro de Lisboa se encuentra la única boutique Xerjoff de Portugal: un destino para quienes tratan la fragancia como arte y no como costumbre. Fundada en Turín, Xerjoff trabaja con ingredientes excepcionales y técnicas artesanales que muy pocos perfumistas en el mundo dominan. Cada frasco es una declaración de gusto. Cada composición, un descubrimiento.',
  'Xerjoff representa la cima de la perfumería de autor: cada frasco es una obra, cada fragancia una declaración de intenciones. En una ciudad saturada de perfumerías de centro comercial, esta boutique es un caso aparte.',
  'Porque en un mundo de masificación, Xerjoff elige la rareza como principio. Los ingredientes son excepcionales. La atención es silenciosamente perfecta. Y el espacio fue diseñado para convertir cada visita en una experiencia, no en una compra.',
  'Pida probar la colección Sospiro en sesión privada — algunas de las composiciones más elaboradas de la casa rara vez están en los expositores principales. El personal se esmera en presentar el recorrido creativo de cada fragancia.'
)
ON CONFLICT (place_id, locale) DO UPDATE SET
  name = EXCLUDED.name, short_description = EXCLUDED.short_description,
  full_description = EXCLUDED.full_description, goldenbook_note = EXCLUDED.goldenbook_note,
  why_we_love_it = EXCLUDED.why_we_love_it, insider_tip = EXCLUDED.insider_tip, updated_at = now();


-- ── 2. DAVID ROSAS – Avenida da Liberdade ───────────────────
INSERT INTO place_translations
  (place_id, locale, name, short_description, full_description,
   goldenbook_note, why_we_love_it, insider_tip)
VALUES (
  '4dcd7eb9-2926-b7a7-170f-3e2a41954926', 'es',
  'DAVID ROSAS',
  'La mayor tienda de alta joyería y relojería del país, en la arteria más elegante de Lisboa.',
  'La tienda David Rosas en la Avenida da Liberdade es el espacio de referencia de la alta joyería y relojería en Portugal. Tres plantas de arquitectura elegante, universos masculino y femenino cuidadosamente separados, y una selección de las marcas más prestigiosas del mundo: Patek Philippe, Rolex, Panerai, Chanel, Hermès, Chopard, Hublot y las propias creaciones de la casa. Un destino para quien reconoce la diferencia entre comprar y elegir.',
  'Tres plantas de excelencia absoluta: alta joyería, relojes de colección y un servicio de atención que rara vez se encuentra fuera de Ginebra o París. David Rosas no vende objetos — crea relaciones duraderas con el tiempo y con el lujo.',
  'Porque David Rosas ha construido décadas de confianza con quienes entienden de joyería y relojería seria en Portugal. La selección de marcas es irreprochable y el conocimiento del personal va mucho más allá del catálogo.',
  'La tercera planta está reservada a piezas de alta joyería y a algunas referencias de relojería que no están expuestas en las plantas inferiores. Merece la pena pedir acceso — la visita es discreta, el nivel de las piezas es otro.'
)
ON CONFLICT (place_id, locale) DO UPDATE SET
  name = EXCLUDED.name, short_description = EXCLUDED.short_description,
  full_description = EXCLUDED.full_description, goldenbook_note = EXCLUDED.goldenbook_note,
  why_we_love_it = EXCLUDED.why_we_love_it, insider_tip = EXCLUDED.insider_tip, updated_at = now();


-- ── 3. FASHION CLINIC WOMEN ──────────────────────────────────
INSERT INTO place_translations
  (place_id, locale, name, short_description, full_description,
   goldenbook_note, why_we_love_it, insider_tip)
VALUES (
  '6e1d294c-84e1-3481-3de1-31111831fa81', 'es',
  'FASHION CLINIC WOMEN',
  'La selección de más de cincuenta marcas de moda de lujo para mujer en Lisboa.',
  'Fashion Clinic Women reúne más de cincuenta marcas de moda de lujo, fragancias y lifestyle en un espacio diseñado para la mujer que no necesita explicaciones. De Moncler a Valentino, de Max Mara a Balenciaga, la selección está hecha con el ojo afinado de un editor de moda que sabe lo que funciona en esta ciudad.',
  'Fashion Clinic tiene la mirada de un editor de moda: aquí no encontrará lo obvio, sino la selección que alguien con muy buen gusto haría por usted. En un único espacio, las mejores maisons — dispuestas con la claridad de quien sabe lo que vende.',
  'Por la amplitud sin excesos y por la forma en que el espacio facilita la decisión. Las colecciones conversan entre sí. La iluminación es honesta. El resultado es una tienda de la que rara vez se sale con las manos vacías.',
  'Las novedades de temporada llegan frecuentemente antes de estar disponibles en las webs de las marcas. La primera planta suele tener piezas que aún no han llegado al radar del gran público.'
)
ON CONFLICT (place_id, locale) DO UPDATE SET
  name = EXCLUDED.name, short_description = EXCLUDED.short_description,
  full_description = EXCLUDED.full_description, goldenbook_note = EXCLUDED.goldenbook_note,
  why_we_love_it = EXCLUDED.why_we_love_it, insider_tip = EXCLUDED.insider_tip, updated_at = now();


-- ── 4. FASHION CLINIC MEN ────────────────────────────────────
INSERT INTO place_translations
  (place_id, locale, name, short_description, full_description,
   goldenbook_note, why_we_love_it, insider_tip)
VALUES (
  '8242da11-2654-8460-e3c1-7efe8da02051', 'es',
  'FASHION CLINIC MEN',
  'La selección de más de cincuenta marcas de moda, fragancias y lifestyle para hombre.',
  'Fashion Clinic Men presenta una de las selecciones de moda de lujo masculina más completas de Portugal. De Brioni a Moncler, de Canali a Dsquared2 — cada colección ha sido elegida por quien entiende lo que distingue una prenda memorable de una prenda simplemente cara. El espacio facilita la decisión: limpio, bien iluminado, sin ruido visual.',
  'Lo mejor del vestuario masculino de lujo bajo el mismo techo, sin concesiones de calidad. Del traje de ceremonia al casual de primera línea, Fashion Clinic Men tiene lo que hace falta y poco más — lo que, en este caso, es un elogio.',
  'Porque aquí encontrará desde el traje de ceremonia hasta la chaqueta de viaje ideal, con la certeza de que cada prenda ha sido seleccionada con genuino rigor editorial, no por cuota de marcas ni acuerdos comerciales.',
  'Los estilistas de la tienda conocen las colecciones con profundidad real. Pida asesoramiento directamente — la competencia es genuina y el servicio no es invasivo.'
)
ON CONFLICT (place_id, locale) DO UPDATE SET
  name = EXCLUDED.name, short_description = EXCLUDED.short_description,
  full_description = EXCLUDED.full_description, goldenbook_note = EXCLUDED.goldenbook_note,
  why_we_love_it = EXCLUDED.why_we_love_it, insider_tip = EXCLUDED.insider_tip, updated_at = now();


-- ── 5. EMBASSY ───────────────────────────────────────────────
INSERT INTO place_translations
  (place_id, locale, name, short_description, full_description,
   goldenbook_note, why_we_love_it, insider_tip)
VALUES (
  '61e14af7-8768-cbf5-dab2-753e2bbbf17b', 'es',
  'EMBASSY',
  'La mejor selección de perfumería nicho de Lisboa, en un espacio íntimo y sin prisas.',
  'En Embassy, el perfume se trata como arte, expresión e identidad. Un espacio dedicado exclusivamente a casas de fragancias independientes — marcas que eligen la libertad creativa por encima de las tendencias. El ambiente es sofisticado e íntimo, la atención es personalizada y el tiempo tiene otro ritmo. Muchas de las marcas aquí representadas son exclusivas de este espacio en Portugal.',
  'En Embassy, el perfume se trata como arte: cada frasco representa una decisión creativa, no una fórmula de mercado. Es aquí donde Lisboa descubre las casas que aún no han llegado a ninguna otra tienda del país.',
  'Por el rigor de la selección y la rareza de las marcas. Entrar en Embassy es tener acceso a un universo olfativo que la mayoría de las personas nunca encontrará en un centro comercial. Eso, en Lisboa, es mucho.',
  'Llegue sin prisa y diga lo que siente, no lo que busca. El personal trabaja por asociación sensorial y rara vez falla en la lectura. Reserve al menos cuarenta y cinco minutos para la primera visita.'
)
ON CONFLICT (place_id, locale) DO UPDATE SET
  name = EXCLUDED.name, short_description = EXCLUDED.short_description,
  full_description = EXCLUDED.full_description, goldenbook_note = EXCLUDED.goldenbook_note,
  why_we_love_it = EXCLUDED.why_we_love_it, insider_tip = EXCLUDED.insider_tip, updated_at = now();


-- ── 6. FUNDAÇÃO AMÁLIA RODRIGUES ─────────────────────────────
INSERT INTO place_translations
  (place_id, locale, name, short_description, full_description,
   goldenbook_note, why_we_love_it, insider_tip)
VALUES (
  'e3720f28-1703-14f8-9a7a-292f3b1dd992', 'es',
  'FUNDAÇÃO AMÁLIA RODRIGUES',
  'La casa donde Amália vivió, preservada como memoria viva del fado y del alma portuguesa.',
  'La Fundação Amália Rodrigues ocupa el edificio del siglo XVIII donde la mayor voz del fado vivió durante décadas. Más que un museo, es una visita a la memoria de una mujer que conquistó los mayores escenarios internacionales sin dejar nunca de ser de Lisboa. El espacio preserva el día a día y los objetos personales de Amália con una dignidad que conmueve a cualquiera que entre.',
  'Entrar en esta casa es encontrar Lisboa como ella se sueña a sí misma: intensa, melancólica y profundamente humana. La Fundação Amália no es un museo — es una peregrinación al corazón del fado.',
  'Porque Amália no pertenece al pasado. Pertenece a la ciudad, a las calles y al fado que aún se escucha en las noches de Lisboa. Esta fundación nos recuerda por qué la música puede ser más grande que quien la hace.',
  'Las visitas guiadas revelan detalles de la vida privada de Amália que nunca aparecen en los textos de pared. Las plazas son limitadas y se agotan rápido — reserve con antelación.'
)
ON CONFLICT (place_id, locale) DO UPDATE SET
  name = EXCLUDED.name, short_description = EXCLUDED.short_description,
  full_description = EXCLUDED.full_description, goldenbook_note = EXCLUDED.goldenbook_note,
  why_we_love_it = EXCLUDED.why_we_love_it, insider_tip = EXCLUDED.insider_tip, updated_at = now();


-- ── 7. ELEMENTS 75'80 LISBOA ─────────────────────────────────
INSERT INTO place_translations
  (place_id, locale, name, short_description, full_description,
   goldenbook_note, why_we_love_it, insider_tip)
VALUES (
  '5cc082ec-5cc0-c90f-518b-956762b9d2d4', 'es',
  'ELEMENTS 75''80 LISBOA',
  'Joyería contemporánea de autor, creada por gemólogos con pasión genuina por las piedras que eligen.',
  'Elements 75''80 fue fundada por los hermanos Nuno y Marco dos Santos, gemólogos con una pasión por las piedras preciosas que se percibe en cada pieza de la casa. El atelier de Lisboa ofrece joyería contemporánea de autor, creación a medida, transformación de piezas antiguas y servicios de gemología — desde la identificación de piedras hasta la certificación de colecciones.',
  'Elements 75''80 es la prueba de que la joyería portuguesa contemporánea puede rivalizar con las grandes casas europeas. Cada pieza se piensa desde cero, cada piedra se elige a mano. El conocimiento es genuino y se nota.',
  'Porque Nuno y Marco no venden joyas como se venden artículos — las presentan con el contexto de las piedras, los orígenes y las decisiones de diseño detrás de cada pieza. Esa diferencia es palpable.',
  'Si tiene una piedra de familia o una pieza por transformar, venga a conversar antes de decidir. El servicio de creación a medida es el verdadero diferencial de esta casa — y el presupuesto inicial es sin compromiso.'
)
ON CONFLICT (place_id, locale) DO UPDATE SET
  name = EXCLUDED.name, short_description = EXCLUDED.short_description,
  full_description = EXCLUDED.full_description, goldenbook_note = EXCLUDED.goldenbook_note,
  why_we_love_it = EXCLUDED.why_we_love_it, insider_tip = EXCLUDED.insider_tip, updated_at = now();


-- ── 8. BARBOUR ───────────────────────────────────────────────
INSERT INTO place_translations
  (place_id, locale, name, short_description, full_description,
   goldenbook_note, why_we_love_it, insider_tip)
VALUES (
  '0178bf45-a60d-6a63-c2aa-6c2d409985d4', 'es',
  'BARBOUR',
  'La chaqueta encerada más famosa del mundo, fabricada a mano en Gran Bretaña desde 1894.',
  'Barbour fabrica sus icónicas chaquetas enceradas a mano en la fábrica de Simonside desde el siglo XIX. Los tartanes exclusivos de la marca, creados en colaboración con el maestro Kinloch Anderson, rastrean a la familia Barbour hasta el siglo XIII. Más que moda, es artesanía con fecha de nacimiento — y que mejora con el uso.',
  'Barbour no sigue tendencias — les sobrevive. Una chaqueta de esta casa dura décadas y gana carácter con el tiempo, como todo lo que está bien hecho. En una industria dominada por la obsolescencia programada, es un caso aparte.',
  'Por la durabilidad que confronta de frente la cultura de lo desechable. Una prenda Barbour es una inversión con nombre propio — y la marca aún la repara e impermeabiliza gratuitamente, independientemente de la antigüedad de la chaqueta.',
  'Cualquier chaqueta Barbour antigua puede devolverse a la marca para ser impermeabilizada y reparada. Un servicio que ninguna otra marca de moda ofrece de la misma manera. Pregunte en la tienda por el programa de rewaxing.'
)
ON CONFLICT (place_id, locale) DO UPDATE SET
  name = EXCLUDED.name, short_description = EXCLUDED.short_description,
  full_description = EXCLUDED.full_description, goldenbook_note = EXCLUDED.goldenbook_note,
  why_we_love_it = EXCLUDED.why_we_love_it, insider_tip = EXCLUDED.insider_tip, updated_at = now();


-- ── 9. MARLENE VIEIRA ────────────────────────────────────────
INSERT INTO place_translations
  (place_id, locale, name, short_description, full_description)
VALUES (
  '5cb490e4-e5bd-37f7-8e84-c02c2a46c949', 'es',
  'MARLENE VIEIRA',
  'Un espacio irreverente, vibrante y rebelde, con una fuerte atracción por la novedad.',
  'Es el reflejo de mis memorias y convicciones, en una mezcla de tradición e innovación.
Es la unión de mi saber con el deseo de proporcionar experiencias memorables. En este espacio depurado, se sirve un viaje gastronómico que es reflejo de mi aprendizaje, en una búsqueda de cocina portuguesa moderna, con preocupaciones de sostenibilidad y estacionalidad.
Marlene es un espacio irreverente, vibrante y rebelde, con una fuerte atracción por la novedad. Es una cocina de autor en la que el enfoque técnico hace brillar los ingredientes en su esencia.
Esta es una experiencia única que se traduce en actos simples, como comer y compartir.
Bienvenidos a Marlene.

La Chef Marlene Vieira
La conexión con la cocina de la chef Marlene Vieira comenzó muy pronto y actualmente acumula 28 años de experiencia en el sector. Siempre ligada a lo mejor de la cocina portuguesa.
El Zunzum Gastrobar que la chef Marlene Vieira abrió en la Terminal de Cruceros de Lisboa es claro en su enfoque y ejecución. Aquí tenemos Portugal en la mesa, con productos nacionales y técnicas del mundo, en una cocina que tiene tanto de intemporal como de moderna.'
)
ON CONFLICT (place_id, locale) DO UPDATE SET
  name = EXCLUDED.name, short_description = EXCLUDED.short_description,
  full_description = EXCLUDED.full_description, updated_at = now();


