-- Route 1: Lisbon Luxury Icons
INSERT INTO route_translations
  (id, route_id, locale, title, summary, body)
SELECT
  gen_random_uuid(), r.id, 'es',
  'Iconos del Lujo de Lisboa',
  'Un recorrido curado por las direcciones de lujo más refinadas de Lisboa.',
  'Algunas ciudades tienen unas pocas direcciones de lujo. Lisboa tiene una constelación. '
  'Esta ruta conecta las boutiques y talleres más codiciados de la ciudad — '
  'desde una casa de fragancias raras creada en Turín hasta la mayor tienda de alta joyería del país, '
  'pasando por una selección de moda que rivaliza con las mejores del continente. '
  'Reserve dos horas y media. Muévase despacio. '
  'No es una sesión de compras — es una educación en el buen gusto.'
FROM routes r WHERE r.slug = 'lisbon-luxury-icons'
ON CONFLICT (route_id, locale) DO UPDATE SET
  title = EXCLUDED.title, summary = EXCLUDED.summary, body = EXCLUDED.body, updated_at = now();

-- Route 2: A Quiet Lisbon Afternoon
INSERT INTO route_translations
  (id, route_id, locale, title, summary, body)
SELECT
  gen_random_uuid(), r.id, 'es',
  'Una Tarde Tranquila en Lisboa',
  'Reduzca el ritmo y descubra el alma cultural de Lisboa, una parada sin prisa a la vez.',
  'No todas las tardes en Lisboa deben ser apresuradas. '
  'Esta ruta existe para las horas en que la luz se vuelve dorada y la ciudad respira hondo. '
  'Comienza donde el fado encontró su voz y una leyenda guarda aún su silencio, '
  'continúa hacia un taller donde la joyería contemporánea portuguesa se presenta sin artificios, '
  'y termina en una casa británica que Lisboa adoptó como suya hace generaciones. '
  'Tres paradas. Tres horas. Sin agenda más allá de la presencia.'
FROM routes r WHERE r.slug = 'quiet-lisbon-afternoon'
ON CONFLICT (route_id, locale) DO UPDATE SET
  title = EXCLUDED.title, summary = EXCLUDED.summary, body = EXCLUDED.body, updated_at = now();


